INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('acl_state8_sliders_update_readout_not_geometry', 'STATE_8 explorer: I/r sliders update only the B readout — the 2πr ruler, bar length and loop do NOT respond (visual contradicts narration)', 'MAJOR', 'peter_parker:renderer_primitives', 'In the amperes_circuital_law STATE_8 integrated/slider state the live I and r sliders are bound only to the numeric B readout (B = mu_0*I/(2*pi*r) updates correctly). The geometry is static: changing r does not lengthen the 2pi*r ruler/bar or resize the Amperian loop, and changing I changes nothing visual. The narration explicitly promises "the 2pi*r ruler gets longer" and "B falls as 1/r" — so the picture contradicts the spoken lesson (teach_visual_must_match_narration).', 'In the explorer/integrated state bind the live r slider to the on-screen geometry: the 2pi*r ruler length and the Amperian loop radius must grow/shrink with r, and B must visibly fall as 1/r. Never let an explorer state move only a numeric readout while its geometry stays frozen.', 'manual', 'Open STATE_8, drag r from min to max: the ruler/bar must visibly lengthen and the loop must enlarge while I_enc holds; drag I: B visibly tracks. The geometry must change, not just the number.', 'FIXED', ARRAY['amperes_circuital_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_amperes_review', 'incident'),
('acl_unrolled_bar_occludes_loop_and_wire', 'STATE_6/7/8 unrolled bar + 2πr ruler anchored at canvas centre cuts through the Amperian loop and the wire (occlusion / hindrance)', 'MAJOR', 'peter_parker:renderer_primitives', 'The unrolled bar + ruler is anchored at the vertical centre of the canvas, where the Amperian loop and the current-carrying wire also live, so the bar overlaps and obstructs both (founder: "this is stopping the view of the rod and the circle"). In the 16:9 reviewer view the overlap is pronounced — bar, loop and wire compete for the same band.', 'Anchor the unrolled bar + ruler in a clear gutter (e.g. a dedicated lower band) fully separated from the loop and wire; relocate/raise or fade the loop+wire when the bar is the focus. No primitive should occlude another in the unroll/solve/explore states.', 'manual', 'In STATE_6/7/8 the bar, the Amperian loop, and the wire are each fully visible with no overlap; the bar sits clear of the loop and rod.', 'FIXED', ARRAY['amperes_circuital_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_amperes_review', 'incident'),
('acl_state7_visually_indistinct_from_state6', 'STATE_7 (solve for B) reads as identical to STATE_6 — same static bar, only the equation box changes; the "isolate B" beat does not land', 'MAJOR', 'peter_parker:renderer_primitives', 'STATE_6 (unroll -> B·2pi*r) and STATE_7 (set = mu_0*I_enc, solve for B) share the same dominant visual: the identical horizontal green bar. Only the top equation box and a small "= mu_0*I_enc" change, so the divide-by-2pi*r / isolate-B step is a re-caption of the same picture, not a distinct beat (founder: "state 7 is same with state 6 ... not working").', 'Give STATE_7 a distinct visual move for the solve step: visibly divide the bar by 2pi*r / cancel the 2pi*r length and extract B, so the isolate-B action is a different picture from STATE_6, not the same static bar with new text.', 'manual', 'STATE_6 and STATE_7 are visually distinguishable at a glance; STATE_7 shows an isolate-B action (a divide/cancel/extract), not the STATE_6 bar with a swapped caption.', 'FIXED', ARRAY['amperes_circuital_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_amperes_review', 'incident'),
('acl_unroll_ring_to_bar_transformation_unclear', 'STATE_6 ring→bar "unroll" is hard to follow ("the circle is molded into a column") — the circle-becomes-a-line transformation does not read', 'MODERATE', 'peter_parker:renderer_primitives', 'The unroll that turns the ring of equal B·dl tiles into the straight 2pi*r bar is not legible: it is compounded by the bar overlapping the loop (see acl_unrolled_bar_occludes_loop_and_wire) and by the transformation not visibly lifting the tiles off the loop and straightening them. Founder could not tell what was happening and questioned whether the unroll is needed vs directly stating the circumference is 2pi*r. [architect/pedagogy note: the unroll is correct physics — keep it, but make the circle->line transformation unmistakable; if still unclear after the layout fix, fall back to a "highlight the loop circumference, label it 2pi*r" beat.]', 'Make the ring->bar unroll unmistakable: visibly lift the tiles off the loop and straighten them into a clearly-separated bar of the same total length, so a first-time viewer sees the circle becoming the line (length conserved). Keep the unroll only if it reads; otherwise use the simpler "the path once around = 2pi*r" beat.', 'manual', 'A first-time viewer watching STATE_6 can see the loop tiles lift off and straighten into one bar of the same total length = 2pi*r, with the loop and bar clearly separate.', 'FIXED', ARRAY['amperes_circuital_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_amperes_review', 'incident')
ON CONFLICT (bug_class) DO NOTHING;
